static MAX_WIDGET_LINES = 10;

setExtensionWidget(key, content, options) {
    // ...
    if (Array.isArray(content)) {
        const container = new Container();
        // SLICE to MAX_WIDGET_LINES вҖ” HARD TRUNCATION
