}

renderWidgetContainer(container, widgets, spacerWhenEmpty, leadingSpacer) {
    container.clear();
    if (widgets.size === 0) {
        if (spacerWhenEmpty) container.addChild(new Spacer(1));
        return;
    }
    if (leadingSpacer) container.addChild(new Spacer(1));
