function renderPlanLines(): string[] {
  if (!planState) return [];
  const { goal, steps, startTime } = planState;
  const elapsed = Date.now() - startTime;
  const elapsedStr = formatDuration(elapsed);
  const total = steps.length;
  const completedCount = steps.filter(s => s.completed).length;
  const erroredCount = steps.filter(s => s.errored).length;
  const goalTrunc = goal.length > 55 ? goal.slice(0, 52) + "..." : goal;

  const lines: string[] = [];

  // Header
  const prog = erroredCount > 0
    ? `в—Ҹ ${completedCount}/${total} вң—${erroredCount}`
    : `в—Ҹ ${completedCount}/${total}`;
  lines.push(`в—Ҷ ${goalTrunc}  ${prog}  ${elapsedStr}`);

  const activeStep = steps.find(s => s.active);
  const BUDGET = 9; // max step lines (widget caps at 10 total)

  // Collect step display rows: errored first, then completed, skip active (shown last)
  const rows: { icon: string; label: string }[] = [];
  for (const s of steps) {
    if (s === activeStep) continue;
    if (s.errored) rows.push({ icon: 'вң—', label: s.label });
    else if (s.completed) rows.push({ icon: 'вң“', label: s.label });
    else if (!s.active) rows.push({ icon: 'в—Ӣ', label: s.label }); // pending but not active
  }

  // Trim oldest rows if over budget (leave 1 for active step)
  const activeLine = activeStep
    ? `${SPINNER_FRAMES[_spinnerIndex % SPINNER_FRAMES.length]} ${activeStep.label}`
    : null;
  const maxRows = activeLine ? BUDGET - 1 : BUDGET;

  if (rows.length > maxRows) {
    const hidden = rows.length - maxRows;
    // Remove oldest rows, keep newest
    const kept = rows.slice(hidden);
    // Insert "N more" indicator at the front of kept
    if (kept.length > 0) {
      lines.push(`  ... +${hidden} more`);
      for (const r of kept) lines.push(`  ${r.icon} ${r.label}`);
    }
  } else {
    for (const r of rows) lines.push(`  ${r.icon} ${r.label}`);
  }

  if (activeLine) lines.push(`  ${activeLine}`);

  return lines;
}
